def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        base_priority = 0
        threshold = int(np.floor(ratio * 4))
        if ratio > 7:
            for a in range(7, 3, -1):
                for b in range(1, a+4):
                    part1 = np.tanh((ratio - a) ** 4) * np.sin(b * ratio / (a + 0.7))
                    part2 = np.exp(-0.5 * (item / (cap + 1))) * np.cos(ratio * b * 0.9)
                    base_priority += (part1 + part2) / (a + b * 0.5)
            base_priority += np.power(np.abs(np.sin(ratio * 7)), 3) * np.log(ratio + 1)
        elif 4 < ratio <= 7:
            for p in range(1, threshold + 5):
                for q in range(1, p + 3):
                    val = ((ratio - p) ** 2.5) * np.cos(ratio * q) / (q + p * 0.3)
                    base_priority += np.tanh(val ** 1.3) * 1.5
            base_priority += np.log1p(ratio) * 8 - np.tanh(ratio - 4) * 3.2
        elif 2 <= ratio <= 4:
            s1 = 0
            for r in range(1, 14):
                term = ((ratio - 2) ** r) / (r * 1.5) * np.sin(r * ratio * 1.2)
                s1 += term
            s2 = 0
            for s in range(1, 9):
                s2 += np.cos(s * ratio ** 1.1) / (s + 0.7)
            base_priority = s1 * np.cos(6 * ratio) - np.log(ratio + 0.1) * 7 + np.tanh(3 * (4 - ratio)) * 2 + s2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 11):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.sin(n * ratio * 2)
            penalty = 0
            if cap < item * 1.2:
                penalty = np.sqrt(item / (cap + 0.2)) * 3.7
            else:
                penalty = np.cos(15 * ratio) * 3
            base_priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 6):
                base_priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1) ** m) / (m + 0.3)
        elif 0.5 <= ratio < 1:
            s = 0
            for t in range(1, 16):
                s += ((1 - ratio) ** t) / (t * 3) * np.cos(t * ratio * 1.5)
            base_priority = s
            if (i + int(item * 2)) % 5 == 0:
                base_priority *= np.log1p(cap + 2) * 1.7
            else:
                base_priority /= (np.sqrt(cap + 1.7) + 1.5)
            for j in range(1, 7):
                base_priority += ((1 - ratio) ** j) * np.sin(j * item * 1.3) * 0.85
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 13):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.3)
            base_priority = s + 1 / (cap + 2)
            if int(item * 1.6) % 6 == 0:
                base_priority *= 2.8
            else:
                base_priority /= 2.8
            if cap < item * 0.3:
                base_priority += np.log1p(item * cap) * 3.6
            else:
                base_priority -= np.exp(-ratio * 1.5) * 2.7
            for m in range(1, 9):
                base_priority += ((0.5 - ratio) ** m) / (m * 5) * np.cos(item * m * 1.4)
        else:
            s = 0
            for u in range(1, 11):
                s += ((0.2 - ratio) ** u) / (u * 4) * np.sin(u * item * 1.1)
            base_priority = s + 3 / (cap + 5)
            if int(item) % 7 == 0:
                base_priority *= 3.3
            else:
                base_priority /= 3.3
            if cap < item * 0.2:
                base_priority += np.log1p(item * cap) * 4.7
            else:
                base_priority -= np.exp(-ratio * 2.5) * 3.5
            for v in range(1, 10):
                base_priority += ((0.2 - ratio) ** v) / (v * 6) * np.cos(item * v * 0.7)
        if cap < item * 0.5:
            base_priority += np.log1p(item * cap * cap) * 6
        elif cap > item * 3:
            base_priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                base_priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                base_priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 4 == 0:
            base_priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            base_priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = base_priority
    return priorities
